# Data models implementing core interfaces
from core_types import Status, Priority, IDataProcessor, IValidatable, ISized

# Base processor class implementing the interface
class BaseProcessor:
    name: str
    status: Status

    def __init__(self, name: str):
        self.name = name
        self.status = Status.PENDING

    @virtual
    def get_info(self) -> str:
        return f"Processor: {self.name}"

# Concrete processor implementing the interface
class TextProcessor(IDataProcessor, IValidatable, ISized):
    content: str
    _items: list[str]

    def __init__(self):
        self.content = ""
        self._items = []

    def process(self, data: str) -> str:
        result: str = data.upper()
        self._items.append(result)
        return result

    def is_valid(self) -> bool:
        return len(self._items) > 0

    def size(self) -> int:
        return len(self._items)

# Extended processor with additional functionality
class AdvancedProcessor(TextProcessor):
    priority: Priority

    def __init__(self, prio: Priority):
        super().__init__()
        self.priority = prio

    @override
    def process(self, data: str) -> str:
        base: str = data.upper()
        result: str = f"[{self.priority_name(self.priority)}] {base}"
        self._items.append(result)
        return result

    @override
    def get_info(self) -> str:
        return f"Advanced Processor - Priority: {self.priority_name(self.priority)}"

# Helper function to create a processor
def create_processor() -> TextProcessor:
    return TextProcessor()
